/**
 * @summary Get available pickup dates
 */
export const getGetAvailableDatesUrl = (params?: GetAvailableDatesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/config/available-dates?${stringifiedParams}`
    : `/api/config/available-dates`;
};

export const getAvailableDates = async (
  params?: GetAvailableDatesParams,
  options?: RequestInit,
): Promise<AvailableDates> => {
  return customFetch<AvailableDates>(getGetAvailableDatesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetAvailableDatesQueryKey = (
  params?: GetAvailableDatesParams,
) => {
  return [`/api/config/available-dates`, ...(params ? [params] : [])] as const;
};

